mapper.select:
SELECT knowledge_point_name,session_id,create_time FROM chat_message
WHERE sort = 1 AND is_finish =1

    AND user_id = #{userId}

SELECT
cm.session_id as sessionId,
kb.name as baseName,
cm.knowledge_point_name as firstQuestionName,
cm.create_time as createTime
FROM chat_message cm
LEFT JOIN knowledge_base kb ON cm.knowledge_base_id = kb.id
WHERE cm.sort = 1 AND cm.is_finish = 1

    AND cm.knowledge_base_id = #{knowledgeBaseId}


    AND cm.user_id = #{userId}


    AND cm.create_time >= #{startTime}


    AND cm.create_time <= #{endTime}

ORDER BY cm.create_time DESC

SELECT kp.id as knowledgePointId, kp.title as knowledgePointName, COUNT(DISTINCT cm.session_id) as interviewCount, COUNT(cm.id) as questionCount, AVG(CAST(JSON_EXTRACT(cm.comment, '$.score') AS DECIMAL(10,2))) as avgScore FROM chat_message cm LEFT JOIN knowledge_point kp ON cm.knowledge_point_id = kp.id WHERE cm.role = 'user' AND cm.finish_comment = 1
AND cm.knowledge_base_id = #{knowledgeBaseId}
GROUP BY kp.id, kp.title ORDER BY interviewCount DESC
